metrics.sample_kql_for_detection:
let res = SecurityAlert
| where ProductName in ("Qualys","Snyk","Wiz")
| where AlertSeverity in ("Critical","High")
| extend vuln_key = coalesce(AlertId, tostring(Entities[0].Id), strcat(ProductName,":",AlertName))
| summarize firstSeen = min(TimeGenerated) by vuln_key, ProductName;
// Join with a remediation table (ingested from ticketing) to compute MTTR

etl_processes.transform_examples_sql:
SELECT vuln_key, MIN(observed_at) as firstSeen, MAX(observed_at) as lastSeen, COUNT(*) as occurrences, any(ProductName) as source
FROM silver.vuln_findings_normalized
GROUP BY vuln_key;
